mapper.insert:
insert into knowledge_base (
    project_id, name, domain, status, description, created_by, updated_by
) values (
    #{projectId}, #{name}, #{domain}, #{status}, #{description}, #{createdBy}, #{updatedBy}
)

mapper.select:
select 
from knowledge_base
where project_id = #{projectId}
  and deleted = 0

    and status = #{status}


    and domain = #{domain}


    and (name like concat('%', #{keyword}, '%')
         or description like concat('%', #{keyword}, '%'))

order by created_at desc, id desc

mapper.update:
update knowledge_base
set status = #{status}, updated_by = #{updatedBy}
where id = #{knowledgeBaseId}
  and deleted = 0

update knowledge_base
set deleted = 1, updated_by = #{updatedBy}
where id = #{knowledgeBaseId}
  and deleted = 0
